mapper.select:
SELECT seat_label,
	   seat_status
FROM seat_tbl
WHERE show_id = #{showId}
AND schedule_id = #{scheduleId, jdbcType=VARCHAR}
AND seat_status IN ('HELD', 'RESERVED')

SELECT 
seat_label as seatLabel,
seat_id as seatId,
seat_status as seatStatus
FROM seat_tbl
WHERE show_id=#{showId, jdbcType=VARCHAR}
AND schedule_id = #{scheduleId, jdbcType=INTEGER}
AND seat_label = #{seatLabel, jdbcType=VARCHAR}
AND seat_status IN ('HELD', 'RESERVED')
FOR UPDATE
